/**
 * Tests for pdf-to-images.ts
 *
 * Valida o módulo de conversão de PDF para imagens de página.
 * Como pdftoppm não está disponível neste ambiente sandbox,
 * os testes validam tratamento de erro e contratos da API.
 */

import { convertPdfToImages, checkPdfDependencies } from '@/lib/pptx/pdf-to-images';
import * as fs from 'fs/promises';
import * as path from 'path';

const TEMP_BASE = path.join(process.cwd(), '.test-tmp');

describe('pdf-to-images', () => {
  beforeAll(async () => {
    await fs.mkdir(TEMP_BASE, { recursive: true });
  });

  afterAll(async () => {
    await fs.rm(TEMP_BASE, { recursive: true, force: true }).catch(() => {/* ignore */});
  });

  describe('checkPdfDependencies', () => {
    it('should return dependency status', async () => {
      const result = await checkPdfDependencies();

      expect(result).toHaveProperty('pdftoppm');
      expect(result).toHaveProperty('pdfinfo');
      expect(result).toHaveProperty('ready');
      expect(result).toHaveProperty('message');
      expect(typeof result.pdftoppm).toBe('boolean');
      expect(typeof result.pdfinfo).toBe('boolean');
      expect(typeof result.ready).toBe('boolean');
      expect(typeof result.message).toBe('string');

      if (result.pdftoppm) {
        expect(result.ready).toBe(true);
      } else {
        expect(result.ready).toBe(false);
        expect(result.message).toContain('poppler-utils');
      }
    });
  });

  describe('convertPdfToImages', () => {
    it('should return error for non-existent file', async () => {
      const result = await convertPdfToImages('/nonexistent/file.pdf');

      expect(result.success).toBe(false);
      expect(result.images).toEqual([]);
      expect(result.totalPages).toBe(0);
      expect(result.error).toContain('Input file not found');
    });

    it('should handle missing pdftoppm gracefully', async () => {
      const tmpDir = await fs.mkdtemp(path.join(TEMP_BASE, 'pdf-test-'));
      const tmpFile = path.join(tmpDir, 'test.pdf');
      await fs.writeFile(tmpFile, '%PDF-1.4 fake content');

      try {
        const result = await convertPdfToImages(tmpFile);

        if (!result.success) {
          expect(result.error).toBeDefined();
          expect(result.images).toEqual([]);
          expect(result.totalPages).toBe(0);
          const errorLower = (result.error ?? '').toLowerCase();
          expect(
            errorLower.includes('pdftoppm') ||
            errorLower.includes('poppler') ||
            errorLower.includes('not installed')
          ).toBe(true);
        }
      } finally {
        await fs.rm(tmpDir, { recursive: true, force: true });
      }
    });

    it('should accept page range options', async () => {
      const tmpDir = await fs.mkdtemp(path.join(TEMP_BASE, 'pdf-test-'));
      const tmpFile = path.join(tmpDir, 'test.pdf');
      await fs.writeFile(tmpFile, '%PDF-1.4 fake content');

      try {
        const result = await convertPdfToImages(tmpFile, {
          firstPage: 1,
          lastPage: 5,
          width: 1280,
          height: 720,
          format: 'jpeg',
        });

        expect(result).toHaveProperty('success');
        expect(result).toHaveProperty('images');
        expect(result).toHaveProperty('totalPages');
      } finally {
        await fs.rm(tmpDir, { recursive: true, force: true });
      }
    });

    it('should match page count with generated images', async () => {
      // This test validates the comparison logic in the converter
      const result = await convertPdfToImages('/nonexistent.pdf');
      expect(result.totalPages).toBe(result.images.length);
    });
  });
});
